def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 6):
            term = (ratio ** j) / j
            if j % 2 == 0:
                term *= 1.5
            else:
                term *= 0.75
            score += term
        if capacity > 10 * item:
            score *= 0.4
            for k in range(3):
                score += (0.1 / (k + 1)) * np.sin(ratio * (k + 1) * np.pi)
        elif capacity > 5 * item:
            score *= 0.7
            for k in range(2, 5):
                score -= (0.05 * k) * np.cos(ratio * k * np.pi / 2)
        else:
            if capacity < item * 0.8:
                score *= 2.5
            elif capacity < item:
                score *= 1.8
            else:
                for m in range(1, 4):
                    score += (ratio ** m) * np.log1p(m)
        if score < 0:
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
    else:
        max_priority = 1
    for i in range(len(priorities)):
        if np.isinf(priorities[i]):
            priorities[i] = max_priority * 15
    return priorities
